bool ReadMemory(HANDLE hProcess, uintptr_t address, void* buffer, size_t size) {
    SIZE_T bytesRead = 0;
    if (!ReadProcessMemory(hProcess, reinterpret_cast<LPCVOID>(address),
                          buffer, size, &bytesRead)) {
        std::cerr << "ReadProcessMemory failed: " << GetLastError() << "\n";
        return false;
    }
    return bytesRead == size;
}

