std::optional<uintptr_t> PatternScan(
    const uint8_t* region, size_t regionSize,
    const char* pattern, const char* mask)
{
    size_t patLen = strlen(mask);
    for (size_t i = 0; i + patLen <= regionSize; ++i) {
        bool found = true;
        for (size_t j = 0; j < patLen; ++j) {
            if (mask[j] == 'x' && region[i + j] != static_cast<uint8_t>(pattern[j])) {
                found = false;
                break;
            }
        }
        if (found) return reinterpret_cast<uintptr_t>(region + i);
    }
    return std::nullopt;
}

