#include <windows.h>
#include <cstdint>

bool ValidatePE(const uint8_t* base) {
    auto dos = reinterpret_cast<const IMAGE_DOS_HEADER*>(base);
    if (dos->e_magic != IMAGE_DOS_SIGNATURE) // "MZ"
        return false;

    auto nt = reinterpret_cast<const IMAGE_NT_HEADERS*>(base + dos->e_lfanew);
    if (nt->Signature != IMAGE_NT_SIGNATURE) // "PE"
        return false;

    return true;
}

uint32_t GetImageSize(const uint8_t* base) {
    auto dos = reinterpret_cast<const IMAGE_DOS_HEADER*>(base);
    auto nt = reinterpret_cast<const IMAGE_NT_HEADERS*>(base + dos->e_lfanew);
    return nt->OptionalHeader.SizeOfImage;
}

// Given object pointer at runtime:
// object -> vtable -> function pointers

template<typename Ret, typename... Args>
Ret CallVFunc(void* object, int index, Args... args) {
    auto vtable = *reinterpret_cast<uintptr_t**>(object);
    auto func = reinterpret_cast<Ret(*)(void*, Args...)>(vtable[index]);
    return func(object, args...);
}

// Example: read vtable[3] without calling
uintptr_t GetVFuncAddress(void* object, int index) {
    auto vtable = *reinterpret_cast<uintptr_t**>(object);
    return vtable[index];
}

