bool InjectDLL(HANDLE hProcess, const char* dllPath) {
    size_t pathLen = strlen(dllPath) + 1;
    void* remoteMem = VirtualAllocEx(hProcess, nullptr, pathLen,
                                     MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
    if (!remoteMem) return false;

    WriteProcessMemory(hProcess, remoteMem, dllPath, pathLen, nullptr);

    auto loadLib = reinterpret_cast<LPTHREAD_START_ROUTINE>(
        GetProcAddress(GetModuleHandleA("kernel32.dll"), "LoadLibraryA"));

    HANDLE hThread = CreateRemoteThread(hProcess, nullptr, 0, loadLib, remoteMem, 0, nullptr);
    if (!hThread) return false;

    WaitForSingleObject(hThread, INFINITE);
    CloseHandle(hThread);
    VirtualFreeEx(hProcess, remoteMem, 0, MEM_RELEASE);
    return true;
}

#include <windows.h>

// Set DR0 to break on execution at address (current thread context)
bool SetHWBreakpoint(HANDLE hThread, uintptr_t address, int drIndex = 0) {
    CONTEXT ctx{};
    ctx.ContextFlags = CONTEXT_DEBUG_REGISTERS;
    if (!GetThreadContext(hThread, &ctx)) return false;

    switch (drIndex) {
        case 0: ctx.Dr0 = address; break;
        case 1: ctx.Dr1 = address; break;
        case 2: ctx.Dr2 = address; break;
        case 3: ctx.Dr3 = address; break;
        default: return false;
    }
    // Enable local breakpoint: L0-L3 bits in Dr7
    ctx.Dr7 |= (1 << (drIndex * 2));       // local enable
    ctx.Dr7 &= ~(0xF << (16 + drIndex * 4)); // clear condition
    // 00 = break on execution

    return SetThreadContext(hThread, &ctx);
}

#include <windows.h>
#include <cstring>

FARPROC GetExportByName(uint8_t* moduleBase, const char* funcName) {
    auto dos = reinterpret_cast<IMAGE_DOS_HEADER*>(moduleBase);
    auto nt = reinterpret_cast<IMAGE_NT_HEADERS*>(moduleBase + dos->e_lfanew);
    auto& exportDir = nt->OptionalHeader.DataDirectory[IMAGE_DIRECTORY_ENTRY_EXPORT];
    if (!exportDir.VirtualAddress) return nullptr;

    auto exports = reinterpret_cast<IMAGE_EXPORT_DIRECTORY*>(
        moduleBase + exportDir.VirtualAddress);
    auto names = reinterpret_cast<DWORD*>(moduleBase + exports->AddressOfNames);
    auto ordinals = reinterpret_cast<WORD*>(moduleBase + exports->AddressOfNameOrdinals);
    auto functions = reinterpret_cast<DWORD*>(moduleBase + exports->AddressOfFunctions);

    for (DWORD i = 0; i < exports->NumberOfNames; ++i) {
        const char* name = reinterpret_cast<const char*>(moduleBase + names[i]);
        if (strcmp(name, funcName) == 0) {
            DWORD rva = functions[ordinals[i]];
            return reinterpret_cast<FARPROC>(moduleBase + rva);
        }
    }
    return nullptr;
}

#include <windows.h>
#include <winternl.h>

// Link with ntdll or use direct syscall in research VMs
typedef NTSTATUS(NTAPI* NtQueryInformationProcess_t)(
    HANDLE, PROCESSINFOCLASS, PVOID, ULONG, PULONG);

uintptr_t GetPebAddress(HANDLE hProcess) {
    PROCESS_BASIC_INFORMATION pbi{};
    auto NtQueryInformationProcess = reinterpret_cast<NtQueryInformationProcess_t>(
        GetProcAddress(GetModuleHandleA("ntdll.dll"), "NtQueryInformationProcess"));
    if (!NtQueryInformationProcess) return 0;

    NTSTATUS status = NtQueryInformationProcess(
        hProcess, ProcessBasicInformation, &pbi, sizeof(pbi), nullptr);
    if (status != 0) return 0;
    return reinterpret_cast<uintptr_t>(pbi.PebBaseAddress);
}
